const raw = $input.first().json;
let time = '';
let message = 'Reminder!';
let chatId = raw.chatId || raw.telegram_chat_id || raw.chat_id || '';
try {
  const parsed = JSON.parse(raw.query || '{}');
  time = parsed.time || raw.time || '';
  message = parsed.message || raw.message || 'Reminder!';
  chatId = parsed.chatId || parsed.chat_id || chatId;
} catch (error) {
  time = raw.time || '';
  message = raw.message || 'Reminder!';
}
const date = new Date(time);
if (Number.isNaN(date.getTime())) {
  return [{ json: { error: 'Invalid ISO timestamp supplied for the reminder.' } }];
}
const hour = date.getHours();
const minute = date.getMinutes();
const apiKey = process.env.N8N_API_KEY || '';
const wf = {
  name: 'Reminder ' + message.substring(0, 30),
  nodes: [
    {
      parameters: { rule: { interval: [{ triggerAtHour: hour, triggerAtMinute: minute }] } },
      name: 'Timer', type: 'n8n-nodes-base.scheduleTrigger', typeVersion: 1.2, position: [0, 0]
    },
    {
      parameters: { chatId: String(chatId), text: '⏰ ' + message, additionalFields: {} },
      name: 'Notify', type: 'n8n-nodes-base.telegram', typeVersion: 1.2, position: [220, 0],
      credentials: { telegramApi: { id: 'REPLACE_WITH_YOUR_CREDENTIAL_ID', name: 'Telegram Bot' } }
    },
    {
      parameters: {
        method: 'POST',
        url: '={{$env.N8N_INTERNAL_URL}}/api/v1/workflows/{{$workflow.id}}/deactivate',
        sendHeaders: true,
        headerParameters: { parameters: [{ name: 'X-N8N-API-KEY', value: '={{$env.N8N_API_KEY}}' }] },
        options: {}
      },
      name: 'Cleanup', type: 'n8n-nodes-base.httpRequest', typeVersion: 4.2, position: [440, 0]
    }
  ],
  connections: {
    Timer: { main: [[{ node: 'Notify', type: 'main', index: 0 }]] },
    Notify: { main: [[{ node: 'Cleanup', type: 'main', index: 0 }]] }
  },
  settings: { executionOrder: 'v1' }
};
return [{ json: { body: wf, hour, minute, msg: message, chatId: String(chatId), apiKeyLength: apiKey.length } }];
